-- Enrichment marathon batch: Open-Meteo, openarchiver, OpenCart, OpenCATS, OpenCloud, OpenCTI, OpenEMR, OpenFGA

-- ── Open-Meteo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-Meteo is a free, open-source weather forecast API that blends data from more than 15 national weather services into one developer-friendly interface, with no API key required for non-commercial use.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Burglen, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Open-Meteo Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Open-Meteo review 2026: pricing tiers, forecast accuracy, historical data access, self-hosting options, and the best alternatives to this open-source weather API.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Open-Meteo is a free, open-source weather forecast API launched in 2022 by meteorologist and developer Patrick Zippenfenig through OpenMeteo GmbH, based in Burglen, Switzerland. Its core differentiator is data aggregation: rather than running its own proprietary forecast model, Open-Meteo ingests and blends open numerical weather prediction data from more than 15 national meteorological services, including NOAA (United States), DWD (Germany), ECMWF (Europe), the UK Met Office, Meteo-France, JMA (Japan), KMA (Korea), KNMI (Netherlands), DMI (Denmark), MeteoSwiss, BOM (Australia), CMA (China), and GeoSphere Austria, then normalizes them into a single consistent JSON API. This gives developers high-resolution local and global forecasts without needing to integrate a dozen separate government data feeds. The platform processes more than 2 terabytes of weather data daily. Open-Meteo's flagship feature is that its API requires no API key and no signup for non-commercial use, with a free tier allowing up to 300,000 calls per month, 10,000 per day, and 5,000 per hour. Beyond current and 16-day forecasts, Open-Meteo offers specialized endpoints for historical weather archives spanning decades, marine and ocean weather, air quality, flood forecasting, and climate change projection data. Its full source code is published on GitHub under an open license, letting technical teams self-host or audit the pipeline, which appeals to privacy-conscious developers and those wary of vendor lock-in. Commercial use requires a paid subscription, sold not per API call but as a fixed monthly call budget across API Standard (1M calls per month), API Professional (5M calls per month), and API Enterprise (50M+ calls per month, custom pricing) tiers, with no per-call overage charges. Its primary audience is software developers, data scientists, agritech and logistics teams, and hobbyists building weather-dependent apps, dashboards, or research pipelines who want an accurate, low-cost or free alternative to commercial weather APIs like OpenWeatherMap, Tomorrow.io, Weatherbit, or Visual Crossing. Because it is run by a small independent team rather than a large corporation, Open-Meteo competes primarily on price, transparency, and breadth of open meteorological data sources rather than enterprise SLAs, though enterprise support is available on request.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cd709a3d-fa5f-4189-82f4-95c1e1fdb2f0';

