-- ── OpenCATS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenCATS is a free, open-source applicant tracking system and recruiting CRM that helps staffing agencies and hiring teams manage candidates, job requisitions, and the placement pipeline in a self-hosted system.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Community-maintained (no single company)$q$, company_size),
  headquarters = COALESCE($q$Distributed open-source community (no headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenCATS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenCATS review 2026: features, self-hosting requirements, pricing, pros and cons, and how this open-source ATS compares to modern recruiting software.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenCATS is a free, open-source applicant tracking system (ATS) and recruiting CRM designed for staffing agencies, internal recruiting teams, and hiring managers who want to manage the full recruitment lifecycle without paying per-seat SaaS fees. Its origins trace back to a commercial open-source recruiting product called CATS, which split into separate commercial and community-driven efforts; the open-source OpenCATS project that resulted from that split dates to around 2007-2009, making it one of the oldest and most widely recognized open-source ATS platforms still in active use, often described as the default answer whenever someone searches for an open-source applicant tracking system. Rather than being backed by a single venture-funded company, OpenCATS is maintained in the open by a community of users and contributors on GitHub, with development, bug fixes, and feature requests handled through public repositories rather than a corporate roadmap. Functionally, it covers the core recruiting workflow end to end: candidate records with resumes, notes, and status history; job order and requisition management; company and contact management for staffing agency clients; a searchable candidate database; pipeline tracking from application through submission, interview, and placement; and basic reporting on recruiting activity. Because it is self-hosted (typically on a LAMP-style PHP and MySQL stack), organizations install and run OpenCATS on their own servers, giving them full control over recruiting data, no per-recruiter licensing cost, and no dependency on a vendor's continued existence, which appeals particularly to smaller staffing agencies, nonprofits, and government or education hiring teams operating under tight software budgets or strict data residency requirements. Its tradeoffs versus modern commercial ATS platforms like Greenhouse, Lever, Bullhorn, or JobDiva are a more dated user interface, fewer out-of-the-box integrations (career site builders, job board syndication, AI resume parsing, calendaring), and reliance on the community or third-party consultants for setup, hosting, and support rather than a vendor support contract. There is no official SaaS-hosted version or tiered commercial pricing; the software itself is entirely free, with any cost limited to self-hosting infrastructure and optional paid implementation help from independent consultants. OpenCATS remains a relevant choice specifically for organizations that prioritize data ownership and zero licensing cost over polish and modern integrations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '448ec905-8c58-4b0c-931b-b7bedf89db12';

