-- ── OpenCTI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenCTI is an open-source cyber threat intelligence platform that helps security teams ingest, correlate, and visualize threat data from multiple sources using the STIX2 standard, developed by French company Filigran.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Enterprise Edition custom pricing$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Filigran: approximately 200 employees (as of late 2025)$q$, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$OpenCTI Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenCTI review 2026: threat intelligence features, STIX2 data model, Community vs Enterprise Edition pricing, and how it compares to other CTI platforms.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenCTI is an open-source cyber threat intelligence (CTI) platform used by security operations and intelligence teams to ingest, structure, correlate, and visualize threat data from commercial feeds, internal telemetry, and open-source intelligence into one unified view. The project originated in 2018 inside ANSSI, the French National Agency for the Security of Information Systems, which built it internally to store and structure its own knowledge about cyber threats in cooperation with CERT-EU. The tool was later open-sourced and placed under Luatix, a nonprofit created specifically to govern the project, with ANSSI as a founding member. In 2022, the company Filigran was founded in Paris by Samuel Hassine (CEO) and Julien Richard (CTO) to become the commercial steward of OpenCTI and its companion product OpenBAS (an attack simulation and breach-and-attack-simulation platform, since rebranded OpenAEV). OpenCTI structures threat data using the STIX2 (Structured Threat Information Expression) knowledge schema, letting analysts model indicators, threat actors, malware, campaigns, and their relationships, then correlate that data across sources and visualize it in an investigation-friendly interface. Filigran has raised substantial venture funding to grow the platform: a EUR5 million seed round in 2023 led by Moonfire, a EUR15 million (~$16 million) Series A in February 2024 led by Accel, a $35 million Series B in October 2024 led by Insight Partners, and a $58 million Series C in October 2025 led by Eurazeo with participation from Deutsche Telekom, bringing total funding to over $100 million in roughly three years. The company has grown from about 40 employees in 2024 to nearly 200 by late 2025, and OpenCTI and OpenBAS together are used by more than 6,000 public and private organizations, including government agencies like the FBI and the European Commission, and enterprises such as Airbus and Hermes. OpenCTI is offered as a free, fully functional open-source Community Edition, while an Enterprise Edition adds enterprise-grade scalability, automated playbooks, priority intelligence requirements (PIRs), AI-powered file import, report generation, and NLP search, with pricing available only through a private sales quote and a 30-day free trial. Its target audience is security operations centers, threat intelligence teams, CERTs and government cybersecurity agencies, and enterprises building in-house threat intelligence programs, competing with commercial platforms like Recorded Future, ThreatConnect, Anomali, and MISP (another open-source alternative), differentiating through its French/EU government origins, STIX2-native data model, and rapid, well-funded product development.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '51b8b175-b3a3-4820-80ba-3b5c9cb31c4e';

