-- ── OpenFGA ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenFGA is a free, open-source fine-grained authorization engine inspired by Google's Zanzibar paper, originally built by Auth0/Okta and now a CNCF Incubating project used to add scalable permissions to applications.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$CNCF community project (maintained by Okta and Grafana engineers)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (originating sponsor: Okta/Auth0)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenFGA Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenFGA review 2026: fine-grained authorization features, Zanzibar-inspired architecture, SDKs, self-hosting, pricing, and how it compares to other tools.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenFGA is a free, open-source fine-grained authorization (FGA) engine designed to let developers implement scalable, relationship-based permission systems in their applications. It was designed, built, and open-sourced by Auth0, the identity platform acquired by Okta, drawing directly on the ideas in Google's 2019 Zanzibar paper, which described the global authorization system Google built to power consistent, low-latency permission checks across products like Google Drive and YouTube. Auth0/Okta announced OpenFGA and donated it to the Cloud Native Computing Foundation (CNCF) in September 2022, initially as a Sandbox project; it has since advanced to CNCF Incubating status, reflecting growing adoption and a maturing governance model with an open RFC process for community contributions. Technically, OpenFGA lets engineering teams define an authorization model in a purpose-built modeling language that can express relationship-based access control (ReBAC, the core Zanzibar-style approach), while also supporting role-based access control (RBAC) and attribute-based access control (ABAC) patterns within the same system, which means teams do not need separate tools for simple role checks versus complex nested permission relationships such as 'a user can edit a document if they are an editor on a folder that contains it.' It is built for high performance, designed to answer authorization check calls in milliseconds even at scale, and ships with SDKs for popular languages and frameworks including Python, Java, Spring, and Next.js, plus integrations with identity providers such as Auth0, Okta, and Azure AD, and with infrastructure tools like OPA (Open Policy Agent), the Envoy proxy, and the Kong API gateway. Because it is entirely open source and free, teams can self-host the OpenFGA server themselves; Okta also offers a hosted commercial version through Auth0 FGA for teams that prefer a managed service. Companies publicly known to use OpenFGA include Grafana, Docker, and Canonical, and the project is jointly maintained by engineers from Okta and Grafana Labs under CNCF governance rather than a single company's roadmap. OpenFGA's target audience is backend and platform engineering teams building applications with complex, multi-tenant, or hierarchical permission requirements, such as SaaS products with organizations, teams, and shared resources, positioning it as a modern alternative to building bespoke authorization logic in-house or to commercial authorization platforms like Ory Keto, Permit.io, or AuthZed's SpiceDB, which is also a Zanzibar-inspired open-source system.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '801862d9-7d0d-4545-aa0d-0e249ca2ab37';

